22	export interface ProdiaProviderSettings {
23	  /**
24	   * Prodia API key. Default value is taken from the `PRODIA_TOKEN` environment variable.
25	   */
26	  apiKey?: string;
27	
28	  /**
29	   * Base URL for the API calls. Defaults to `https://inference.prodia.com/v2`.
30	   */
31	  baseURL?: string;
32	
33	  /**
34	   * Custom headers to include in the requests.
35	   */
36	  headers?: Record<string, string>;
37	
38	  /**
39	   * Custom fetch implementation. You can use it as a middleware to intercept
40	   * requests, or to provide a custom fetch implementation for e.g. testing.
41	   */
42	  fetch?: FetchFunction;
43	}
44	
45	export interface ProdiaProvider extends ProviderV3 {
46	  /**
47	   * Creates a language model for multimodal generation (img2img with text+image output).
48	   */
49	  languageModel(modelId: ProdiaLanguageModelId): LanguageModelV3;
50	
51	  /**
52	   * Creates a model for image generation.
53	   */
54	  image(modelId: ProdiaImageModelId): ImageModelV3;
55	
56	  /**
57	   * Creates a model for image generation.
58	   */
59	  imageModel(modelId: ProdiaImageModelId): ImageModelV3;
60	
61	  /**
62	   * Creates a model for video generation.
63	   */
64	  video(modelId: ProdiaVideoModelId): Experimental_VideoModelV3;
65	
66	  /**
67	   * Creates a model for video generation.
68	   */
69	  videoModel(modelId: ProdiaVideoModelId): Experimental_VideoModelV3;
70	
71	  /**
72	   * @deprecated Use `embeddingModel` instead.
73	   */
74	  textEmbeddingModel(modelId: string): never;
75	}
76	
77	const defaultBaseURL = 'https://inference.prodia.com/v2';
78	
79	export function createProdia(
80	  options: ProdiaProviderSettings = {},
81	): ProdiaProvider {
82	  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);
83	  const getHeaders = () =>
84	    withUserAgentSuffix(
85	      {
86	        Authorization: `Bearer ${loadApiKey({
87	          apiKey: options.apiKey,
88	          environmentVariableName: 'PRODIA_TOKEN',
89	          description: 'Prodia',
90	        })}`,
91	        ...options.headers,
92	      },
93	      `ai-sdk/prodia/${VERSION}`,
94	    );
95	
96	  const createImageModel = (modelId: ProdiaImageModelId) =>
97	    new ProdiaImageModel(modelId, {
98	      provider: 'prodia.image',
99	      baseURL: baseURL ?? defaultBaseURL,
100	      headers: getHeaders,
101	      fetch: options.fetch,
102	    });
103	
104	  const createLanguageModel = (modelId: ProdiaLanguageModelId) =>
105	    new ProdiaLanguageModel(modelId, {
106	      provider: 'prodia.language',
107	      baseURL: baseURL ?? defaultBaseURL,
108	      headers: getHeaders,
109	      fetch: options.fetch,
110	    });
111	
112	  const createVideoModel = (modelId: ProdiaVideoModelId) =>
113	    new ProdiaVideoModel(modelId, {
114	      provider: 'prodia.video',
115	      baseURL: baseURL ?? defaultBaseURL,
116	      headers: getHeaders,
117	      fetch: options.fetch,
118	    });
119	
120	  const embeddingModel = (modelId: string) => {
121	    throw new NoSuchModelError({
122	      modelId,
123	      modelType: 'embeddingModel',
124	    });
125	  };
126	
127	  return {
128	    specificationVersion: 'v3',
129	    languageModel: createLanguageModel,
130	    imageModel: createImageModel,
131	    image: createImageModel,
132	    videoModel: createVideoModel,
133	    video: createVideoModel,
134	    embeddingModel,
135	    textEmbeddingModel: embeddingModel,
136	  };
137	}
138	
139	export const prodia = createProdia();
