1	import { createJsonErrorResponseHandler } from '@ai-sdk/provider-utils';
2	import type { FetchFunction, Resolvable } from '@ai-sdk/provider-utils';
3	import { z } from 'zod/v4';
4	
5	export interface ProdiaModelConfig {
6	  provider: string;
7	  baseURL: string;
8	  headers?: Resolvable<Record<string, string | undefined>>;
9	  fetch?: FetchFunction;
10	  _internal?: {
11	    currentDate?: () => Date;
12	  };
13	}
14	
15	export const prodiaJobResultSchema = z.object({
16	  id: z.string(),
17	  created_at: z.string().optional(),
18	  updated_at: z.string().optional(),
19	  expires_at: z.string().optional(),
20	  state: z
21	    .object({
22	      current: z.string(),
23	    })
24	    .optional(),
25	  config: z
26	    .object({
27	      seed: z.number().optional(),
28	    })
29	    .passthrough()
30	    .optional(),
31	  metrics: z
32	    .object({
33	      elapsed: z.number().optional(),
34	      ips: z.number().optional(),
35	    })
36	    .optional(),
37	  price: z
38	    .object({
39	      product: z.string(),
40	      dollars: z.number(),
41	    })
42	    .nullish(),
43	});
44	
45	export type ProdiaJobResult = z.infer<typeof prodiaJobResultSchema>;
46	
47	export function buildProdiaProviderMetadata(jobResult: ProdiaJobResult) {
48	  return {
49	    jobId: jobResult.id,
50	    ...(jobResult.config?.seed != null && {
51	      seed: jobResult.config.seed,
52	    }),
53	    ...(jobResult.metrics?.elapsed != null && {
54	      elapsed: jobResult.metrics.elapsed,
55	    }),
56	    ...(jobResult.metrics?.ips != null && {
57	      iterationsPerSecond: jobResult.metrics.ips,
58	    }),
59	    ...(jobResult.created_at != null && {
60	      createdAt: jobResult.created_at,
61	    }),
62	    ...(jobResult.updated_at != null && {
63	      updatedAt: jobResult.updated_at,
64	    }),
65	    ...(jobResult.price?.dollars != null && {
66	      dollars: jobResult.price.dollars,
67	    }),
68	  };
69	}
70	
71	export interface MultipartPart {
72	  headers: Record<string, string>;
73	  body: Uint8Array;
74	}
75	
76	export function parseMultipart(
77	  data: Uint8Array,
78	  boundary: string,
79	): MultipartPart[] {
80	  const parts: MultipartPart[] = [];
81	  const boundaryBytes = new TextEncoder().encode(`--${boundary}`);
82	  const endBoundaryBytes = new TextEncoder().encode(`--${boundary}--`);
83	
84	  const positions: number[] = [];
85	  for (let i = 0; i <= data.length - boundaryBytes.length; i++) {
86	    let match = true;
87	    for (let j = 0; j < boundaryBytes.length; j++) {
88	      if (data[i + j] !== boundaryBytes[j]) {
89	        match = false;
90	        break;
91	      }
92	    }
93	    if (match) {
94	      positions.push(i);
95	    }
96	  }
97	
98	  for (let i = 0; i < positions.length - 1; i++) {
99	    const start = positions[i] + boundaryBytes.length;
100	    const end = positions[i + 1];
101	
102	    let isEndBoundary = true;
103	    for (let j = 0; j < endBoundaryBytes.length && isEndBoundary; j++) {
104	      if (data[positions[i] + j] !== endBoundaryBytes[j]) {
105	        isEndBoundary = false;
106	      }
107	    }
108	    if (
109	      isEndBoundary &&
110	      positions[i] + endBoundaryBytes.length <= data.length
111	    ) {
112	      continue;
113	    }
114	
115	    let partStart = start;
116	    if (data[partStart] === 0x0d && data[partStart + 1] === 0x0a) {
117	      partStart += 2;
118	    } else if (data[partStart] === 0x0a) {
119	      partStart += 1;
120	    }
121	
122	    let partEnd = end;
123	    if (data[partEnd - 2] === 0x0d && data[partEnd - 1] === 0x0a) {
124	      partEnd -= 2;
125	    } else if (data[partEnd - 1] === 0x0a) {
126	      partEnd -= 1;
127	    }
128	
129	    const partData = data.slice(partStart, partEnd);
130	
131	    let headerEnd = -1;
132	    for (let j = 0; j < partData.length - 3; j++) {
133	      if (
134	        partData[j] === 0x0d &&
135	        partData[j + 1] === 0x0a &&
136	        partData[j + 2] === 0x0d &&
137	        partData[j + 3] === 0x0a
138	      ) {
139	        headerEnd = j;
140	        break;
141	      }
142	      if (partData[j] === 0x0a && partData[j + 1] === 0x0a) {
143	        headerEnd = j;
144	        break;
145	      }
146	    }
147	
148	    if (headerEnd === -1) {
149	      continue;
150	    }
151	
152	    const headerBytes = partData.slice(0, headerEnd);
153	    const headerStr = new TextDecoder().decode(headerBytes);
154	    const headers: Record<string, string> = {};
155	    for (const line of headerStr.split(/\r?\n/)) {
156	      const colonIdx = line.indexOf(':');
157	      if (colonIdx > 0) {
158	        const key = line.slice(0, colonIdx).trim().toLowerCase();
159	        const value = line.slice(colonIdx + 1).trim();
160	        headers[key] = value;
161	      }
162	    }
163	
164	    let bodyStart = headerEnd + 2;
165	    if (partData[headerEnd] === 0x0d) {
166	      bodyStart = headerEnd + 4;
167	    }
168	    const body = partData.slice(bodyStart);
169	
170	    parts.push({ headers, body });
171	  }
172	
173	  return parts;
174	}
