176	const prodiaErrorSchema = z.object({
177	  message: z.string().optional(),
178	  detail: z.unknown().optional(),
179	  error: z.string().optional(),
180	});
181	
182	export const prodiaFailedResponseHandler = createJsonErrorResponseHandler({
183	  errorSchema: prodiaErrorSchema,
184	  errorToMessage: error => {
185	    const parsed = prodiaErrorSchema.safeParse(error);
186	    if (!parsed.success) return 'Unknown Prodia error';
187	    const { message, detail, error: errorField } = parsed.data;
188	    if (typeof detail === 'string') return detail;
189	    if (detail != null) {
190	      try {
191	        return JSON.stringify(detail);
