describe('PixelArt provider', () => {
  it('creates image models via .image and .imageModel', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });

    const imageModel = provider.image('pixel-art-v1');
    const imageModel2 = provider.imageModel('pixel-art-v2');

    expect(imageModel.provider).toBe('pixelart.image');
    expect(imageModel.modelId).toBe('pixel-art-v1');
    expect(imageModel2.modelId).toBe('pixel-art-v2');
    expect(imageModel.specificationVersion).toBe('v3');
  });

  it('configures baseURL and headers correctly', async () => {
