import { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const prompt = 'A tiny pixel wizard casting a spell';

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixel-art-v1', {
    provider: 'pixelart.image',
    baseURL: 'https://api.example.com/v1',
    headers: headers ?? (() => ({ Authorization: 'Bearer test-key' })),
    fetch,
    _internal: {
      currentDate,
    },
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    'https://api.example.com/v1/images/generations': {
      response: {
        type: 'json-value',
        body: {
          created: 1234567890,
          data: [
            {
              b64_json: 'aGVsbG8=',
            },
          ],
        },
      },
    },
  });

  describe('doGenerate', () => {
    it('sends the correct request body with model and prompt', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toMatchObject({
        model: 'pixel-art-v1',
        prompt,
        n: 1,
        response_format: 'b64_json',
      });
    });

    it('passes style, pixelDensity, and size from providerOptions', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelArt: {
            style: 'retro',
            pixelDensity: 8,
            size: '512x512',
          },
        },
      });

      expect(await server.calls[0].requestBodyJson).toMatchObject({
        style: 'retro',
        pixel_density: 8,
        size: '512x512',
      });
    });

    it('includes seed in request body when provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: 42,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toMatchObject({
        seed: 42,
      });
    });

    it('returns base64 image data from response', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.images).toHaveLength(1);
      expect(result.images[0]).toBe('aGVsbG8=');
    });

    it('includes revisedPrompt in providerMetadata when API returns it', async () => {
      server.urls[
        'https://api.example.com/v1/images/generations'
      ].response = {
        type: 'json-value',
        body: {
          created: 1234567890,
          data: [
            {
              b64_json: 'aGVsbG8=',
              revised_prompt: 'A tiny pixel wizard casting a fireball spell',
            },
          ],
        },
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.providerMetadata?.pixelArt.images[0]).toMatchObject({
        revisedPrompt: 'A tiny pixel wizard casting a fireball spell',
      });
    });

    it('omits revisedPrompt from providerMetadata when not returned by API', async () => {
      server.urls[
        'https://api.example.com/v1/images/generations'
      ].response = {
        type: 'json-value',
        body: {
          created: 1234567890,
          data: [{ b64_json: 'aGVsbG8=' }],
        },
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.providerMetadata?.pixelArt.images[0]).not.toHaveProperty(
        'revisedPrompt',
      );
    });

    it('issues a warning when size parameter is passed', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '1024x1024',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.warnings).toMatchInlineSnapshot(`
        [
          {
            "details": "PixelArt does not support the size parameter. Use providerOptions.pixelArt.size instead.",
            "feature": "size",
            "type": "unsupported",
          },
        ]
      `);
    });

    it('merges provider and request headers', async () => {
      const model = createBasicModel({
        headers: () => ({
          Authorization: 'Bearer test-key',
          'x-provider-header': 'provider-value',
        }),
      });

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        headers: {
          'x-request-header': 'request-value',
        },
      });

      expect(server.calls[0].requestHeaders).toMatchObject({
        authorization: 'Bearer test-key',
        'x-provider-header': 'provider-value',
        'x-request-header': 'request-value',
      });
    });

    it('includes timestamp, headers, and modelId in response', async () => {
      const testDate = new Date('2025-01-01T00:00:00Z');
      const model = createBasicModel({
        currentDate: () => testDate,
      });

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.response).toStrictEqual({
        timestamp: testDate,
        modelId: 'pixel-art-v1',
        headers: expect.any(Object),
      });
    });

    it('handles API error responses', async () => {
      server.urls[
        'https://api.example.com/v1/images/generations'
      ].response = {
        type: 'error',
        status: 400,
        body: JSON.stringify({
          error: { message: 'Invalid style value', type: 'invalid_request' },
        }),
      };

      const model = createBasicModel();

      await expect(
        model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
        }),
      ).rejects.toMatchObject({
        message: 'Invalid style value',
        statusCode: 400,
        url: 'https://api.example.com/v1/images/generations',
      });
    });

    it('ignores unknown providerOptions fields', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelArt: {
            style: 'pixel',
            unknownField: 'should be ignored',
          },
        },
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).not.toHaveProperty('unknownField');
      expect(body).toMatchObject({ style: 'pixel' });
    });
  });

  describe('constructor', () => {
    it('exposes correct provider and model information', () => {
      const model = createBasicModel();

      expect(model.provider).toBe('pixelart.image');
      expect(model.modelId).toBe('pixel-art-v1');
      expect(model.specificationVersion).toBe('v3');
      expect(model.maxImagesPerCall).toBe(1);
    });
  });
});

